query:
ALTER TABLE camps 
ADD COLUMN IF NOT EXISTS freeOffers TEXT COMMENT 'Free offers (one per line)',
ADD COLUMN IF NOT EXISTS discountedOffers TEXT COMMENT 'Discounted offers (one per line)';

-- Copy data from campOffers to freeOffers if exists
UPDATE camps SET freeOffers = campOffers WHERE campOffers IS NOT NULL AND freeOffers IS NULL;

-- Drop old column
ALTER TABLE camps DROP COLUMN IF EXISTS campOffers;

